import { useClans } from '../context/ClanContext';
import { useNavigate } from 'react-router-dom';

export default function CreateClan() {
  const { addClan } = useClans();
  const navigate = useNavigate();

  // your form states here: name, description, etc.

  const handleSubmit = (e) => {
    e.preventDefault();

    const newClan = {
      id: Date.now().toString(),
      name,
      members: 1,
      description,
    };

    addClan(newClan);         // <-- add clan to global state
    console.log('New clan created:', newClan);
    navigate('/clans');       // <-- navigate back to clans page
  };

  // return your form JSX
}
